import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const pragmatismScienceContinuationPhilosopherArticles:Record<string,ArticleSection[]>={
  peirce:[
    section('overview','Pragmatism as a logic of inquiry',[
      `Charles Sanders Peirce is the founder of pragmatism in its most exacting form, but he is easy to misread if pragmatism is taken to mean whatever is useful right now. Peirce wanted a method for clarifying ideas by tracing their conceivable practical bearings within inquiry. Meaning, for him, is tied to habits of action and possible experimental consequences, not to private feelings or verbal definitions alone. His pragmatism begins in logic and scientific method before it becomes a cultural movement.`,
      `Peirce matters because he connected philosophy, logic, mathematics, signs, and the communal practice of science. He treated inquiry as a disciplined movement from genuine doubt toward more stable belief, always under fallible conditions. His work can look fragmentary because many writings were published as articles, lectures, reviews, and manuscripts rather than one neat system. Yet the underlying ambition is broad: to explain how minds, signs, experiments, and communities can orient themselves toward truth without claiming final certainty.`
    ],['pragmatism','logic','philosophy-of-science'],['peirce','william-james','dewey'],['The Fixation of Belief','How to Make Our Ideas Clear']),
    section('life-and-setting','An American thinker between science and philosophy',[
      `Peirce worked in the nineteenth-century United States at a time when scientific institutions, mathematical logic, statistical reasoning, and evolutionary thought were changing the intellectual landscape. He had scientific training, worked for the United States Coast Survey, and moved through circles that cared about measurement, probability, and experimental standards. This background matters because his philosophy was not written from a distance from science. It grew out of practical contact with instruments, error, classification, and public checking.`,
      `His career was also difficult and unstable. Peirce never held the secure academic position that his originality might seem to have deserved, and much of his later work remained scattered. That biographical fact should not become a romance of neglected genius, but it helps explain the shape of the corpus. Readers encounter him through essays and manuscripts where technical logic, metaphysical speculation, and accessible examples appear side by side. The apparent disorder hides a powerful concern with the ordered self-correction of inquiry.`
    ],['pragmatism','philosophy-of-science'],['peirce'],[]),
    section('pragmatic-maxim','The pragmatic maxim and clarified meaning',[
      `Peirce's pragmatic maxim asks us to understand a concept by considering the practical effects that would conceivably follow from the truth of that concept. The point is not to reduce truth to immediate usefulness. It is to remove empty verbal disagreement by asking what difference a belief would make in possible conduct, prediction, experiment, and expectation. If no conceivable difference follows, then the alleged distinction may be confused or merely verbal.`,
      `This method makes philosophy more demanding, not less. A clear idea must be able to guide inquiry, form expectations, and connect with possible experience. Peirce applies the method to issues such as hardness, reality, probability, and truth. The maxim turns meaning toward the future because habits show themselves in what an agent would do under conditions. It also turns meaning toward community because experimental consequences must be available for public testing rather than hidden in private intuition.`
    ],['pragmatism','logic','epistemology'],['peirce','william-james'],['How to Make Our Ideas Clear']),
    section('belief-doubt-inquiry','Belief, doubt, and the irritation that starts inquiry',[
      `In The Fixation of Belief, Peirce describes belief as a settled habit and doubt as an uneasy state that interrupts action. This does not make philosophy a matter of comfort. Genuine doubt is not theatrical uncertainty performed for effect; it is the felt disruption produced when expectations fail or reasons conflict. Inquiry begins because doubt unsettles conduct, and it aims at a belief stable enough to guide action.`,
      `Peirce compares several ways of fixing belief, including tenacity, authority, a priori preference, and scientific inquiry. Tenacity clings to a view; authority enforces one; a priori method follows what seems agreeable to reason at the time. Scientific method is superior because it submits belief to something independent of any one person's preference. The method is social, experimental, and corrigible. It can disappoint the inquirer, and that capacity to disappoint is part of its objectivity.`
    ],['epistemology','philosophy-of-science','pragmatism'],['peirce'],['The Fixation of Belief']),
    section('fallibilism','Fallibilism without surrender',[
      `Peirce's fallibilism says that our beliefs, theories, and even apparently secure methods remain open to correction. Fallibilism is not skepticism in the sense of giving up the search for truth. It is a discipline of humility inside inquiry. Because evidence can be incomplete, instruments can mislead, and concepts can require revision, no human knower should treat present certainty as final possession.`,
      `This is one reason Peirce differs from simple relativism. Fallibility is meaningful only because there is a difference between getting things right and getting them wrong. Inquiry aims beyond what any present community happens to accept. The point is to keep the path of correction open. Peirce's fallibilism therefore joins confidence in the long-run power of inquiry with caution about every particular formulation. It is a philosophy of learning rather than a celebration of uncertainty.`
    ],['epistemology','philosophy-of-science','pragmatism'],['peirce','popper'],[]),
    section('abduction','Abduction, deduction, and induction',[
      `Peirce made a lasting contribution by distinguishing forms of reasoning that work together in inquiry. Deduction draws necessary consequences from hypotheses. Induction tests and estimates by comparing consequences with experience. Abduction proposes explanatory hypotheses in response to surprising facts. Abduction is especially important because inquiry needs more than proof and checking; it needs the creative generation of possible explanations.`,
      `For Peirce, abduction is not a license for arbitrary speculation. A good abductive suggestion must be testable and fruitful enough to enter disciplined investigation. The scientist confronting an unexpected result asks what might explain it, then deduces consequences and tests them inductively. This cycle makes Peirce relevant to later philosophy of science, where discovery, model choice, and theory formation cannot be understood by looking only at confirmation after the fact.`
    ],['logic','philosophy-of-science','pragmatism'],['peirce','popper','kuhn'],['Illustrations of the Logic of Science']),
    section('signs-semiotic','Signs, interpretation, and the growth of meaning',[
      `Peirce's semiotic theory treats signs as triadic relations among sign, object, and interpretant. A sign stands for something to an interpreting effect, and that interpretant can itself become another sign. Meaning therefore develops through chains of interpretation rather than through a simple one-to-one pairing between word and thing. This theory applies not only to language but also to diagrams, symptoms, measurements, gestures, and scientific representations.`,
      `The triadic model matters for pragmatism because inquiry is mediated by signs. We do not confront the world as pure isolated minds receiving uninterpreted data. We use instruments, concepts, notations, classifications, and habits of inference. Peirce's semiotic makes communication and science continuous without reducing science to mere talk. Signs can be better or worse because they can guide successful interpretation, expose error, and connect communities of investigators to objects that resist misunderstanding.`
    ],['logic','philosophy-of-language','pragmatism'],['peirce'],[]),
    section('realism-categories','Realism, categories, and continuity',[
      `Peirce defended a kind of scholastic realism about generals. He rejected the idea that laws, kinds, and general patterns are merely names we impose on unrelated particulars. Scientific inquiry depends on the reality of general features because prediction and explanation assume that patterns are not invented from nothing by the mind. This realism helps separate Peirce from nominalist readings of pragmatism that make all concepts only conveniences.`,
      `His categories of Firstness, Secondness, and Thirdness are difficult but useful. Firstness concerns quality or possibility; Secondness concerns brute encounter, resistance, and reaction; Thirdness concerns mediation, law, habit, and generality. The categories are not a simple table of objects. They are ways of analyzing experience, signs, and nature. Peirce's metaphysics grows from his logic: a world knowable through inquiry must include possibility, resistance, and lawlike mediation.`
    ],['metaphysics','logic','pragmatism'],['peirce','duns-scotus'],[]),
    section('science-community-truth','Truth as the horizon of communal inquiry',[
      `Peirce often connects truth with the opinion that inquiry would ultimately settle on if pursued far enough under proper conditions. This should be handled carefully. He is not saying that truth is whatever people currently agree to, nor that a vote creates reality. He is describing truth through the regulative hope of inquiry: reality is what would continue to constrain investigation no matter who began from error.`,
      `The community is crucial because individual investigators are limited by prejudice, accident, and mortality. Science corrects itself through distributed checking, criticism, measurement, and renewed testing. Peirce's account gives philosophy of science a social dimension before that phrase becomes common. Objectivity is not the absence of persons; it is the achievement of practices that allow personal error to be exposed by a world and a community that exceed the individual.`
    ],['philosophy-of-science','epistemology','pragmatism'],['peirce','dewey','kuhn'],['How to Make Our Ideas Clear']),
    section('james-dewey-relations','Relations to James, Dewey, and later pragmatism',[
      `William James made pragmatism famous, and Peirce later worried that popular versions loosened the method too much. James emphasized lived consequences, pluralism, temperament, religion, and the difference beliefs make in experience. Dewey developed pragmatism as a theory of inquiry, education, democracy, and social reconstruction. Peirce remains the most logically austere member of the early movement, even though the later tradition repeatedly returns to him for depth.`,
      `The differences among the pragmatists are productive. Peirce supplies the logic of signs, inquiry, and fallibilism. James dramatizes the role of belief in lived experience. Dewey places inquiry inside environments, institutions, and publics. Later analytic philosophers, philosophers of science, semioticians, and process thinkers borrow from different parts of this inheritance. Peirce's work is best seen as the technical root of a family of views, not as a slogan that all later pragmatists simply repeat.`
    ],['pragmatism','analytic-philosophy','philosophy-of-science'],['peirce','william-james','dewey','quine'],['Pragmatism','Logic: The Theory of Inquiry']),
    section('probability-continuity','Probability, continuity, and the long run',[
      `Peirce's philosophy of science is also shaped by probability and continuity. He thought inquiry often works under uncertainty, where no single observation settles the matter and reasoning must consider frequencies, error, and the long-run effects of method. This makes him different from philosophers who imagine knowledge as a chain of indubitable steps. Scientific reasoning is experimental, statistical, and self-correcting.`,
      `His interest in continuity, sometimes called synechism, also matters. Peirce resisted pictures of reality as a heap of disconnected atoms, whether in metaphysics, psychology, or logic. Habits grow, signs develop, interpretations lead to further interpretations, and inquiry moves through gradual correction. Continuity does not erase brute resistance or novelty, but it explains why learning can have direction rather than appearing as a series of isolated accidents.`,
      `These themes help beginners see why Peirce is more than the author of one famous maxim. Pragmatism belongs inside a wider architecture of probability, signs, categories, realism, and communal testing. He asks how finite inquiry can be rational when certainty is unavailable. His answer is not to lower the standard of truth, but to trust methods that expose error, preserve continuity of correction, and let consequences accumulate beyond one investigator's life.`
    ],['pragmatism','logic','philosophy-of-science'],['peirce','popper'],['The Doctrine of Chances','The Architecture of Theories']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `The most common misunderstanding is that Peirce makes truth mean practical success. He does not. Practical consequences clarify meaning, while truth remains tied to the object that inquiry would answer to in the long run. Another mistake is to treat his scattered writings as a bag of clever insights. The better approach is to track recurring structures: sign, habit, inference, community, fallibility, and reality.`,
      `Begin with The Fixation of Belief and How to Make Our Ideas Clear, because they show pragmatism in accessible form. Then read essays on the logic of science, abduction, and signs. After that, approach the categories and metaphysics with patience. Peirce rewards slow reading because technical distinctions often serve a humane purpose: to explain how finite, error-prone beings can still participate in a disciplined search for truth.`,
      `A useful classroom route is to ask one question at every stage: what kind of correction does this idea make possible? The pragmatic maxim corrects empty meaning, fallibilism corrects premature certainty, semiotic corrects private theories of thought, and communal inquiry corrects isolated opinion. That question keeps Peirce's technical vocabulary attached to the problem that drives it: how inquiry can be genuinely answerable to reality while remaining an unfinished human practice.`
    ],['pragmatism','logic','philosophy-of-science'],['peirce','william-james','dewey'],['The Fixation of Belief','How to Make Our Ideas Clear','Illustrations of the Logic of Science'])
  ],
  'william-james':[
    section('overview','Pragmatism in the texture of experience',[
      `William James made pragmatism vivid for a broad audience by connecting philosophical ideas with experience, temperament, religion, psychology, and choice. He was not merely a popularizer of Peirce. James transformed pragmatism into a flexible method for asking what difference an idea makes in life. His style is energetic and personal, but the informality should not obscure the philosophical seriousness of his questions about truth, belief, consciousness, and pluralism.`,
      `James matters because he took human finitude seriously without turning philosophy into private taste. We think under pressure, with incomplete evidence, bodily habits, social needs, and moral risks. He asks how belief functions in those conditions. His pragmatism does not tell us to believe whatever is convenient. It asks whether meanings and truths can be understood through the ways ideas work within experience, inquiry, and conduct.`
    ],['pragmatism','epistemology','philosophy-of-mind'],['william-james','peirce','dewey'],['Pragmatism','The Meaning of Truth']),
    section('psychology-context','Psychology before the split from philosophy',[
      `James wrote at a moment when psychology was becoming an experimental and academic field while still carrying deep philosophical questions. The Principles of Psychology studies habit, attention, emotion, will, selfhood, and the stream of consciousness with a combination of empirical observation and philosophical reflection. James does not treat mind as a static container of ideas. He describes mental life as selective, flowing, bodily, and oriented toward action.`,
      `This psychological background shapes his philosophy. Beliefs are not detached labels pasted onto a finished world; they guide attention, expectation, and response. The self is not a simple inner substance easily inspected from within; it is layered through bodily feeling, memory, social recognition, and practical projects. James's pragmatism grows from this dynamic picture of mind. Thinking is something living organisms do while navigating a changing world.`
    ],['philosophy-of-mind','pragmatism','epistemology'],['william-james'],['The Principles of Psychology']),
    section('stream-consciousness','The stream of consciousness and selective attention',[
      `James's phrase stream of consciousness names the flowing, continuous, and selective character of mental life. Experience does not usually arrive as isolated atomic impressions later glued together by a spectator mind. It comes with fringes, transitions, interests, and felt tendencies. We attend to some features and ignore others because living minds are directed toward needs, questions, and possibilities.`,
      `This picture supports James's resistance to overly intellectualized philosophy. Abstract concepts are useful, but they can falsify experience if they turn fluid relations into dead blocks. The stream is not chaos. It has organization through interest, habit, and purpose. James uses psychological description to remind philosophers that knowing is an activity within life, not a view from nowhere. Consciousness selects because organisms must act.`
    ],['philosophy-of-mind','epistemology','pragmatism'],['william-james'],['The Principles of Psychology']),
    section('pragmatic-method','The pragmatic method',[
      `James presents pragmatism as a method for settling philosophical disputes by asking what practical difference would follow if one side rather than another were true. If two doctrines make no difference in experience, expectation, or conduct, the dispute may be verbal. If they do make a difference, that difference should be named clearly. The method is anti-empty-abstraction, not anti-theory.`,
      `Compared with Peirce, James gives the method a wider existential reach. He applies it to metaphysics, religion, freedom, materialism, and pluralism. This expansion made pragmatism influential and controversial. Peirce feared that the term could slide toward loose appeals to usefulness. James, however, is not trying to replace truth with comfort. He wants ideas tested by their roles in the full field of human experience, including inquiry, action, risk, and hope.`
    ],['pragmatism','epistemology'],['william-james','peirce'],['Pragmatism']),
    section('truth','Truth as verification and working',[
      `James's theory of truth is often caricatured as the claim that whatever is useful is true. His actual view is subtler. He emphasizes that true ideas are those that prove themselves good in the way of belief by leading us successfully through experience, connecting with facts, and being verified in practice. Truth happens to an idea as it is confirmed, used, and integrated with other beliefs.`,
      `This account raises real difficulties. Critics worry that James blurs truth with justification, success, or satisfaction. James replies by stressing that beliefs must answer to experience and to the costs of failure. A useful falsehood may produce short-term comfort, but it will not survive the broader discipline of consequences. The best reading treats James as exploring the lived process by which truth becomes available to finite agents rather than offering a simple replacement for correspondence.`
    ],['pragmatism','epistemology'],['william-james','peirce','russell'],['Pragmatism','The Meaning of Truth']),
    section('radical-empiricism','Radical empiricism and relations',[
      `James's radical empiricism holds that experience includes relations as well as discrete things. Traditional empiricism can seem to begin with separate sensations and then ask how the mind connects them. James argues that conjunctive relations, transitions, tendencies, and continuities are also given in experience. We do not first receive a dust of isolated atoms and then invent the world. We encounter a field already rich with movement and connection.`,
      `This view has metaphysical consequences. It supports pluralism, resists both hard materialism and monistic idealism, and makes room for a world of many partly connected processes. It also links James to later process thought and phenomenological concerns, even though his vocabulary differs from both. Radical empiricism is not a refusal of science. It is a demand that philosophy not shrink experience to fit a preconceived account of what data must look like.`
    ],['pragmatism','metaphysics','epistemology'],['william-james','whitehead'],['Essays in Radical Empiricism']),
    section('will-to-believe','The will to believe and decisions under risk',[
      `The Will to Believe addresses cases where evidence is not yet decisive but a decision cannot be indefinitely postponed. James is not defending careless belief. He focuses on live, forced, and momentous options, where refusal to choose is itself a practical choice. In friendship, moral commitment, religious trust, and some forms of collective action, waiting for proof may prevent the very evidence that commitment could help make possible.`,
      `This argument is controversial because it seems to license wishful thinking. James's restriction of the argument matters. He does not claim that anyone may believe anything merely because it is consoling. He asks whether intellectual responsibility includes the courage to act when passivity would close off a real possibility. The essay belongs to his broader picture of human beings as agents whose beliefs sometimes participate in making the conditions they later evaluate.`
    ],['epistemology','pragmatism','philosophy-of-religion'],['william-james','kierkegaard'],['The Will to Believe']),
    section('religious-experience','Religion, temperament, and experience',[
      `In The Varieties of Religious Experience, James studies religion through individual experience rather than primarily through institutions, doctrines, or proofs. He examines conversion, saintliness, mysticism, melancholy, and divided selves. His method is descriptive and evaluative at once: he asks what religious experiences are like and what fruits they bear in life. This approach influenced psychology of religion and philosophical debates about experience and value.`,
      `James does not settle the truth of every religious claim by appeal to experience alone. He is cautious about metaphysical overreach while refusing to dismiss religion as pathology. His question is often pragmatic: what does a belief or experience enable, heal, distort, or demand? This gives his philosophy of religion a distinctive tone. It is sympathetic without being credulous, empirical without being reductionist, and alert to the diversity of human temperaments.`
    ],['philosophy-of-religion','pragmatism','philosophy-of-mind'],['william-james'],['The Varieties of Religious Experience']),
    section('pluralism','Pluralism against the finished absolute',[
      `James resists monistic philosophies that treat reality as one completed rational whole in which individuality, contingency, and conflict are ultimately appearances. He favors a pluralistic universe: unfinished, partly open, containing genuine alternatives and many centers of experience. This does not mean the world is incoherent. It means unity is achieved locally and practically rather than guaranteed in advance by a single system.`,
      `Pluralism also has moral force. If the universe is not already a closed perfection, then action matters. Courage, reform, experiment, and cooperation become real contributions rather than shadows cast by an absolute order. James's pluralism connects metaphysics with temperament: some philosophies satisfy the craving for security, while others preserve risk and novelty. He asks readers to notice how much a metaphysical picture asks them to surrender from actual life.`
    ],['metaphysics','pragmatism','ethics'],['william-james','hegel','whitehead'],['A Pluralistic Universe']),
    section('relations','Peirce, Dewey, and the pragmatist family',[
      `James's relation to Peirce is both indebted and independent. Peirce supplied the original maxim and a logic-centered account of inquiry. James broadened the appeal of pragmatism by writing about truth, religion, pluralism, and the concrete pressures of belief. Dewey later made inquiry more social, educational, and democratic. The movement is not one doctrine repeated by three authors but a conversation about meaning, action, and correction.`,
      `James's influence also extends beyond pragmatism. His psychology shaped later discussions of consciousness, emotion, habit, and selfhood. His radical empiricism interested process philosophers. His account of belief under risk remains important in epistemology and philosophy of religion. Analytic critics often objected to his theory of truth, but even those objections helped define twentieth-century debates over verification, practice, and the relation between belief and reality.`
    ],['pragmatism','philosophy-of-mind','epistemology'],['william-james','peirce','dewey','whitehead'],['The Principles of Psychology','Pragmatism']),
    section('habit-emotion-self','Habit, emotion, and the active self',[
      `James's psychology gives pragmatism a bodily and affective depth. Habit is not merely repetition; it is the way action becomes organized, economical, and available. Habits free attention for new problems, but they can also trap a person in inherited patterns. Because habits are plastic within limits, education and moral effort have real significance. A self is partly the history of what it has learned to do readily.`,
      `His account of emotion also resists simple inner theater models. James famously connects emotion with bodily response, though later psychologists have revised and disputed the details. The philosophical point remains important: feeling is not detached from action, posture, attention, and environment. A person's fear, grief, confidence, or resolve belongs to a whole pattern of bodily life. This reinforces his refusal to separate mind from conduct.`,
      `The self, for James, includes material, social, and spiritual dimensions. We are attached to bodies, possessions, families, reputations, projects, and ideals. This layered view gives his pragmatism psychological realism. Belief is never just an abstract sentence held by a pure intellect. It is held by a person with habits, emotions, loyalties, vulnerabilities, and possible futures. That is why James's philosophy can feel personal without abandoning public argument.`
    ],['philosophy-of-mind','pragmatism','ethics'],['william-james','dewey'],['The Principles of Psychology']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `James is often misunderstood in two opposite ways. Admirers can treat him as permission to trust any life-enhancing belief, while critics can reduce him to a salesman for usefulness. Both miss his attention to risk, experience, correction, and temperament. He is a philosopher of lived inquiry, not a defender of intellectual laziness. His prose is inviting, but the problems under it are severe.`,
      `Begin with Pragmatism for the public statement of method, then read The Will to Believe and selections from The Varieties of Religious Experience. The Principles of Psychology gives the background for habit, attention, and consciousness. Essays in Radical Empiricism is more difficult but important for the metaphysics of relations. Read James with Peirce nearby: the tension between logical discipline and existential breadth is part of the tradition's power.`,
      `It also helps to read James as a philosopher of transition. He stands between older debates over empiricism and idealism, the rise of professional psychology, new religious doubt, and emerging American democratic culture. His questions often begin where neat systems become too narrow for lived experience. That does not make him anti-systematic in a lazy way. It means his system is deliberately plural, experimental, and hospitable to aspects of life that more rigid philosophies treat as embarrassing leftovers.`,
      `For beginners, the best protection against caricature is to keep three Jameses together: the psychologist of habit and attention, the pragmatist of consequences and verification, and the pluralist of risk, religion, and unfinished reality. Separating those figures makes him look inconsistent. Holding them together shows why his account of truth must be read beside his account of persons who need truths in order to act.`
    ],['pragmatism','epistemology','philosophy-of-mind'],['william-james','peirce','dewey'],['Pragmatism','The Will to Believe','The Varieties of Religious Experience','Essays in Radical Empiricism'])
  ],
  dewey:[
    section('overview','Inquiry, democracy, and experience',[
      `John Dewey turns pragmatism into a philosophy of education, democracy, science, ethics, and public life. Where Peirce emphasizes logic and James emphasizes lived experience, Dewey emphasizes inquiry as an adaptive, social, and experimental process. Human beings face problematic situations, use ideas as instruments, test consequences, revise habits, and reshape environments. Philosophy should clarify and improve that process rather than stand above it as a separate court.`,
      `Dewey matters because he refuses to separate knowing from doing. Concepts, values, schools, publics, and scientific methods are all parts of how organisms and communities deal with uncertainty. This makes his thought ambitious and sometimes hard to classify. He is an epistemologist, political philosopher, philosopher of education, social critic, and metaphysician of experience at once. His central question is how intelligent inquiry can help people live together in a changing world.`
    ],['pragmatism','epistemology','political-philosophy'],['dewey','peirce','william-james'],['Reconstruction in Philosophy','Logic: The Theory of Inquiry']),
    section('historical-context','Darwin, industrial society, and democratic strain',[
      `Dewey wrote in the aftermath of Darwin, during the expansion of industrial capitalism, mass schooling, urban growth, labor conflict, and democratic experimentation. Older philosophies often assumed fixed human faculties, fixed social ranks, or fixed ends. Dewey saw human life as historical, developmental, and environmental. Darwinian thinking encouraged him to view organisms as active in adaptation rather than as spectators before a finished world.`,
      `This context explains why education and democracy are not side topics for Dewey. A changing society needs habits of inquiry, communication, and cooperation. If people are trained only to repeat inherited forms, they will be poorly equipped for new problems. If democracy is only a voting mechanism, it will not cultivate the intelligence required for shared life. Dewey's philosophy responds to modernity by asking how communities can learn without losing public responsibility.`
    ],['pragmatism','political-philosophy','philosophy-of-science'],['dewey'],['Democracy and Education','The Public and Its Problems']),
    section('experience-nature','Experience and nature',[
      `Dewey rejects the sharp split between experience and nature. Experience is not a private mental theater sealed off from the world, and nature is not a realm of objects wholly outside human activity. Organisms undergo and respond to environments. They suffer, act, adjust, and transform conditions. Experience includes doing and undergoing, risk and satisfaction, habit and disruption.`,
      `This view changes the task of philosophy. Instead of asking how a mind trapped inside itself can reach an external world, Dewey asks how reflective intelligence arises within transactions between organism and environment. Knowledge is a refined form of this transactional activity. The world is not reduced to experience, but experience is naturalized. Human meaning, value, and thought are continuous with natural processes while still developing distinctive cultural forms.`
    ],['pragmatism','metaphysics','epistemology'],['dewey','william-james'],['Experience and Nature']),
    section('problematic-situation','The problematic situation and inquiry',[
      `For Dewey, inquiry begins in a problematic situation, not in detached doubt about everything. Something in experience becomes uncertain, blocked, unstable, or confusing. The inquirer then defines the problem, imagines possible resolutions, reasons about consequences, acts experimentally, and judges by the transformation of the situation. This model makes inquiry practical without making it shallow.`,
      `Ideas are instruments in this process. They are not merely pictures of reality, nor arbitrary tools chosen for comfort. A good idea helps direct operations that resolve uncertainty and produce warranted conclusions. Dewey's term warranted assertibility stresses that claims earn standing through inquiry under conditions of testing and criticism. This differs from claiming absolute certainty, but it also differs from treating truth as whatever a group happens to prefer.`
    ],['epistemology','philosophy-of-science','pragmatism'],['dewey','peirce'],['Logic: The Theory of Inquiry','How We Think']),
    section('instrumentalism','Instrumentalism and the status of ideas',[
      `Dewey is often called an instrumentalist because he treats concepts and theories as instruments for coping with problems. The label can mislead if it suggests that ideas are disposable tricks. Instruments can be precise, durable, and answerable to their use. A scientific theory, legal concept, or moral principle is evaluated by how it organizes inquiry and action in relation to real consequences.`,
      `Instrumentalism challenges philosophies that treat knowledge as passive contemplation of fixed objects. It also challenges crude utilitarian shortcuts. The value of an instrument depends on the quality of the ends and practices it serves. Dewey's instrumentalism is experimental and public. Ideas must be tested in the consequences they help produce, but those consequences include growth, communication, freedom, and the enrichment of shared experience, not only immediate efficiency.`
    ],['pragmatism','epistemology','philosophy-of-science'],['dewey','william-james'],['Reconstruction in Philosophy','Logic: The Theory of Inquiry']),
    section('education','Education as growth and social intelligence',[
      `Dewey's philosophy of education follows directly from his account of inquiry. Education should not be memorization detached from life, nor vague self-expression without discipline. It should organize experience so that learners develop habits of observation, cooperation, experimentation, and reflection. The classroom becomes a social environment where knowledge is connected with activity and consequences.`,
      `The famous phrase learning by doing is too thin if it means mere activity. Dewey wants meaningful doing: activity guided by questions, materials, feedback, and shared reflection. Growth is not movement toward one fixed adult mold. It is the expansion of capacities for further experience and intelligent participation. This is why education and democracy are linked. A democratic society depends on people able to inquire together rather than merely obey or consume conclusions.`
    ],['pragmatism','political-philosophy','epistemology'],['dewey'],['Democracy and Education','Experience and Education']),
    section('democracy-publics','Democracy and the public',[
      `Dewey understands democracy as more than a form of government. It is a mode of associated living in which people communicate about shared consequences and participate in shaping common life. Modern societies produce indirect, complex consequences through industry, technology, markets, and administration. A public forms when people recognize that they are affected by such consequences and need organized ways to respond.`,
      `The Public and Its Problems argues that democracy is endangered when publics cannot perceive, discuss, and control the forces affecting them. Dewey does not offer nostalgia for small communities. He asks how communication, education, journalism, and institutions might make large-scale democracy more intelligent. His political philosophy is experimental: democracy survives by learning how to identify problems and revise institutions through public inquiry.`
    ],['political-philosophy','pragmatism','ethics'],['dewey','mill'],['The Public and Its Problems']),
    section('ethics-growth','Ethics, habit, and growth',[
      `Dewey's ethics begins from habits, character, situations, and consequences. Moral life is not primarily the application of timeless rules to isolated cases, nor the calculation of pleasure as a single measurable quantity. People inherit habits and institutions, encounter conflicts, imagine possible goods, and deliberate about what kind of life their actions will sustain. Moral judgment is experimental because action reveals consequences that may require revision.`,
      `Growth is Dewey's central ethical ideal, but it should not be confused with endless novelty or personal self-expansion at others' expense. Growth means richer, more connected, more intelligent experience. It includes the ability to communicate, cooperate, learn from conflict, and open possibilities for others. Dewey's ethics therefore joins individual development with social conditions. A society that blocks education, participation, or inquiry damages moral life at its roots.`
    ],['ethics','pragmatism','political-philosophy'],['dewey','mill','aristotle'],['Human Nature and Conduct','Ethics']),
    section('science-technology','Science, technology, and social inquiry',[
      `Dewey admired scientific method because it institutionalizes habits of observation, hypothesis, testing, and revision. He did not think science should replace all values or rule society as a technical priesthood. Rather, the experimental spirit of science should inform public problem-solving. Social problems require inquiry into consequences, causes, institutions, and possible reforms, but those inquiries must remain connected to democratic communication.`,
      `This makes Dewey a major philosopher of science in a broad sense. Scientific knowledge is not a mirror produced by detached spectators. It is an organized practice for transforming indeterminate situations into more stable ones. Technology extends this power but also creates new publics and risks. Dewey's question is how societies can use intelligence without surrendering to technocracy, market drift, or inherited prejudice.`
    ],['philosophy-of-science','pragmatism','political-philosophy'],['dewey','bacon','popper'],['Logic: The Theory of Inquiry','The Public and Its Problems']),
    section('art-aesthetic','Art as intensified experience',[
      `In Art as Experience, Dewey argues that art should not be isolated from ordinary life as a museum object cut off from the conditions that give it meaning. Aesthetic experience arises when doing and undergoing form an integrated, consummatory whole. Art intensifies patterns already present in work, ritual, play, perception, and communication. It reveals what experience can become when materials, emotion, and form are organized.`,
      `This aesthetic theory completes rather than distracts from Dewey's pragmatism. Inquiry, education, democracy, and art all concern the organization of experience. A society that separates fine art from common life impoverishes both. Dewey's point is not that every experience is art, but that the roots of art lie in natural and social rhythms of action and reception. Aesthetic experience becomes evidence for the richness of embodied intelligence.`
    ],['aesthetics','pragmatism'],['dewey'],['Art as Experience']),
    section('communication-community','Communication, community, and public meaning',[
      `Dewey gives communication a central philosophical role. Meaning is not a private object passed from one sealed mind to another. It is formed in shared activity, common symbols, coordinated expectations, and the consequences people learn to recognize together. Language extends experience by making problems public and by allowing the results of inquiry to circulate beyond the original situation. Communication is therefore not an ornament added to thought; it is one of thought's conditions.`,
      `This is why Dewey treats community as epistemically important. A community is not automatically wise, and public opinion can be distorted by propaganda, inequality, and habit. Yet isolated intelligence is too narrow for modern problems. People need institutions that support free communication, expert inquiry, criticism, and access to the consequences of policy. Democratic communication is not mere expression of preference. It is a way of making shared problems visible enough to be intelligently addressed.`,
      `The point also clarifies Dewey's difference from individualistic versions of pragmatism. Consequences matter, but the relevant consequences are often distributed across classrooms, workplaces, neighborhoods, publics, and future generations. An idea that works for one group by hiding costs from another has not passed a serious pragmatic test. Dewey's social pragmatism asks whether inquiry enlarges participation and makes experience more connected, responsible, and educative.`
    ],['pragmatism','political-philosophy','epistemology'],['dewey','william-james','peirce'],['Democracy and Education','The Public and Its Problems']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `Dewey is often misread as a vague progressive optimist who believed every problem can be solved by good intentions. His actual view is more demanding. Inquiry requires discipline, institutions, evidence, and willingness to revise habits. Another misunderstanding is that his rejection of fixed absolutes leaves only relativism. Dewey instead relocates objectivity inside tested, public, corrigible practices.`,
      `Begin with Democracy and Education or Reconstruction in Philosophy for the broad vision. Read How We Think for inquiry in a compact form, then The Public and Its Problems for political philosophy. Experience and Nature and Logic: The Theory of Inquiry are harder but central. Dewey is best approached as a philosopher of organized intelligence: he asks how communities can learn, not merely how individuals can hold correct opinions.`,
      `A good way to test whether Dewey has been understood is to apply him to a concrete institution: a school, a newsroom, a city agency, a laboratory, or a workplace. Ask what problems it helps people perceive, what habits it trains, whose experience it ignores, and how it receives correction. Dewey's abstractions become clearer when they are returned to those settings. His philosophy is not a retreat from public difficulty. It is an attempt to make intelligence social enough to meet it.`,
      `That practical test also shows why Dewey belongs in conversations about philosophy of science. He treats method as a transferable pattern of disciplined experimentation, not as a ritual confined to laboratories. Social inquiry cannot copy physics, because its materials include meanings, institutions, and conflicts. But it can still be empirical, public, and revisable. Dewey's hope is that modern societies can learn to treat their own arrangements as hypotheses open to intelligent reconstruction.`,
      `This is also why Dewey remains useful for contemporary readers. He gives no escape from disagreement, uncertainty, or institutional failure. Instead he asks whether people can design practices that make those difficulties educative rather than destructive. That modest hope is more radical than it first appears.`
    ],['pragmatism','political-philosophy','philosophy-of-science'],['dewey','peirce','william-james'],['Democracy and Education','How We Think','The Public and Its Problems','Experience and Nature'])
  ],
  whitehead:[
    section('overview','From mathematics to process philosophy',[
      `Alfred North Whitehead is unusual because his career moves from mathematics and logic into philosophy of nature, science, metaphysics, education, and civilization. With Bertrand Russell he helped produce Principia Mathematica, one of the central works of logicism. Later he developed a process philosophy in which reality is made of events, occasions, relations, and becoming rather than primarily of static substances.`,
      `Whitehead matters because he tried to think with modern science without accepting a thin picture of nature as mere matter in motion stripped of value, experience, and creativity. His mature philosophy is difficult, but its guiding concern is intelligible: the world disclosed by physics, biology, perception, and history must be understood as one world. Process and relation are not secondary decorations added to things. They are basic features of reality.`
    ],['metaphysics','philosophy-of-science','analytic-philosophy'],['whitehead','russell'],['Principia Mathematica','Process and Reality']),
    section('mathematical-background','Mathematics, logic, and abstraction',[
      `Whitehead's early work in mathematics and logic shaped his later metaphysics. He knew the power of formal abstraction from the inside. Principia Mathematica, written with Russell, aimed to derive large parts of mathematics from logical principles. Even where that project was later transformed by developments in logic, it showed Whitehead's lifelong concern with pattern, relation, order, and the construction of complex systems.`,
      `His later criticism of misplaced concreteness is especially important because it comes from someone who respected abstraction. The fallacy occurs when an abstraction useful for inquiry is treated as the full concrete reality. Scientific models, mathematical structures, and simplified concepts can illuminate, but they can also hide what they leave out. Whitehead does not reject abstraction. He asks philosophers to remember that abstractions are drawn from a richer field of experience and process.`
    ],['logic','metaphysics','philosophy-of-science'],['whitehead','russell'],['Principia Mathematica','Science and the Modern World']),
    section('science-modern-world','Science and the modern world picture',[
      `Whitehead admired the achievements of modern science while criticizing the metaphysical picture sometimes attached to them. Early modern mechanics encouraged a view of nature as externally related bits of matter located in space and time, with color, value, purpose, and feeling treated as merely subjective additions. This bifurcation of nature divides the world into objective quantities and private qualities.`,
      `Whitehead thinks this split cannot be the last word. The red of a sunset, the feel of bodily life, the continuity of perception, and the creativity of organisms are not illusions to be discarded after physics has spoken. They belong to the same nature that science studies. Philosophy must therefore construct a wider scheme in which scientific abstraction and concrete experience can both be respected without reducing one to the other.`
    ],['philosophy-of-science','metaphysics'],['whitehead','descartes','locke'],['Science and the Modern World','The Concept of Nature']),
    section('actual-occasions','Actual occasions and becoming',[
      `Whitehead's mature metaphysics treats actual occasions, or actual entities, as the basic units of reality. These are not tiny enduring substances like miniature particles in the old sense. They are events of becoming, moments of process that gather the past, achieve a determinate form, and perish into objective availability for future occasions. Reality is a society of events rather than a collection of inert things.`,
      `This event-based ontology changes familiar philosophical questions. An enduring object is not a substance that remains identical underneath all change; it is a patterned continuity across many occasions. Causation is not simply external impact among self-contained units; it is inheritance from the past into the becoming of the present. Whitehead's language can be strange, but the point is clear: becoming is not an accident that happens to being. Becoming is fundamental.`
    ],['metaphysics','philosophy-of-science'],['whitehead','heraclitus','leibniz'],['Process and Reality']),
    section('prehension','Prehension, feeling, and relation',[
      `Whitehead uses the term prehension for the basic way an occasion takes account of other realities. Prehension is broader than conscious perception. It names a primitive relation of feeling, reception, or appropriation through which the past is present in a new becoming. Every actual occasion is relational from the start. It is what it becomes by integrating inherited data with its own pattern of satisfaction.`,
      `This makes Whitehead difficult to fit into standard alternatives. He is not saying that electrons have human consciousness, but he is also not treating experience as an inexplicable late addition to dead matter. His view is sometimes called panexperiential rather than panpsychist, because some minimal form of feeling or taking-account belongs widely to reality. The aim is to avoid a sudden magical gap between lifeless mechanism and conscious mind.`
    ],['metaphysics','philosophy-of-mind'],['whitehead','william-james'],['Process and Reality']),
    section('organism-creativity','Organism, creativity, and novelty',[
      `Whitehead's philosophy of organism emphasizes interdependence, internal relation, and the emergence of novelty. Creativity is one of his most basic notions: the many become one and are increased by one. Each occasion inherits from the past but does not merely repeat it. It integrates, emphasizes, excludes, and produces a new fact for the future. Novelty is therefore woven into the structure of reality.`,
      `This helps explain Whitehead's appeal to later ecological, theological, and process thinkers. The world is not a machine assembled from indifferent parts. It is an ongoing production of patterns, organisms, societies, and intensities. Yet Whitehead is not simply offering a poetic alternative to science. He wants a categorial scheme that can make sense of physics, biology, perception, value, and historical change as different abstractions from a processive universe.`
    ],['metaphysics','philosophy-of-science'],['whitehead','dewey'],['Process and Reality','Adventures of Ideas']),
    section('god-possibility','God, possibility, and order',[
      `Whitehead's account of God is one of the most debated parts of his system. God is not the omnipotent ruler of classical popular imagination, nor simply a distant first cause. In Process and Reality, God orders possibilities and is also affected by the world's becoming. This makes divine reality relational, persuasive, and internally connected with temporal process.`,
      `Readers disagree about whether this doctrine is necessary to Whitehead's metaphysics or a speculative extension of it. It became especially important for process theology, which emphasizes divine responsiveness and creaturely freedom. Philosophically, the issue concerns how possibility, order, value, and novelty are grounded. Whitehead's God functions as part of a scheme meant to explain why the world is not mere chaos and why value has ontological depth.`
    ],['metaphysics','philosophy-of-religion'],['whitehead','leibniz'],['Process and Reality','Religion in the Making']),
    section('time-nature','Time, nature, and the critique of simple location',[
      `Whitehead criticizes the idea of simple location, the assumption that a bit of matter is fully where it is at an instant, independent of relations to the rest of nature. This picture works for some scientific abstractions but distorts concrete reality. Events have temporal thickness, inherit histories, and belong to fields of relation. A thing is not fully understood by assigning it coordinates alone.`,
      `The critique matters for philosophy of science because it challenges the metaphysics often smuggled into scientific description. Measurement isolates, but reality connects. Physics itself, especially in the twentieth century, made simple older pictures harder to maintain. Whitehead did not claim that his system simply follows from relativity or quantum theory. He used the changing sciences as pressure to rethink nature in terms of events, fields, and process.`
    ],['philosophy-of-science','metaphysics'],['whitehead','popper','kuhn'],['The Concept of Nature','Science and the Modern World']),
    section('pragmatism-relations','Relations to pragmatism and radical empiricism',[
      `Whitehead is not usually counted as a classical pragmatist, but his thought overlaps with pragmatist concerns. Like James, he resists a world of isolated substances and emphasizes relations, experience, and process. Like Dewey, he rejects a spectator theory of knowledge and treats nature as dynamic. Like Peirce, he values generality, continuity, and the intelligibility of scientific inquiry.`,
      `The differences are also important. Whitehead builds a speculative metaphysical system more openly than Peirce, James, or Dewey usually do. Pragmatists often begin from inquiry and practice; Whitehead begins from the need for a coherent cosmological scheme. Still, the traditions illuminate each other. Pragmatism protects Whitehead from empty abstraction, while Whitehead gives pragmatists a grand metaphysical vocabulary for process, value, and relation.`
    ],['pragmatism','metaphysics','philosophy-of-science'],['whitehead','william-james','dewey','peirce'],['Essays in Radical Empiricism','Experience and Nature','Process and Reality']),
    section('eternal-objects','Eternal objects, possibility, and abstraction',[
      `Whitehead's eternal objects are pure possibilities for definiteness, such as forms, qualities, or patterns that actual occasions may realize. They are not actual things floating in a separate world in a simple Platonic sense. They function within his process metaphysics as ways the actual world can become determinate. Without possibility, the future would be only repetition of the past; without actualization, possibility would remain abstract.`,
      `This doctrine helps explain why mathematics and value both matter in Whitehead's system. Mathematical structures display possible patterns of order, while aesthetic and ethical values concern forms of intensity and harmony that can be realized in experience. Whitehead wants possibility to be objective enough to guide explanation but not detached from becoming. The actual world selects, limits, and embodies possibilities through concrete events.`,
      `For beginners, eternal objects can sound like an unnecessary complication. They become clearer if read alongside Whitehead's warning against misplaced concreteness. Abstractions are not unreal simply because they are abstract, but they are incomplete without the concrete processes that use them. A color, a geometrical relation, or a possible form of order has philosophical significance because actual occasions can take it up and make it part of a real becoming.`
    ],['metaphysics','philosophy-of-science','aesthetics'],['whitehead','plato'],['Process and Reality','Science and the Modern World']),
    section('influence','Influence and contested reception',[
      `Whitehead's influence has been uneven. He is central in process philosophy and process theology, important in some ecological and educational thought, and periodically rediscovered by philosophers interested in events, relations, and science. In mainstream analytic philosophy, his later system was often regarded as too speculative or terminologically forbidding, despite his earlier role in mathematical logic.`,
      `That mixed reception is part of his importance. Whitehead exposes a tension in twentieth-century philosophy between technical analysis and systematic metaphysics. He had credentials in the first and ambition for the second. Readers who find the system excessive can still learn from his warnings about abstraction, his critique of bifurcated nature, and his effort to think science, value, and experience together rather than assigning them to separate worlds.`
    ],['metaphysics','philosophy-of-science','analytic-philosophy'],['whitehead','russell','dewey'],['Science and the Modern World','Process and Reality','Adventures of Ideas']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `Whitehead is often misunderstood either as a mystic opponent of science or as a technical logician who strangely abandoned rigor. Neither picture is fair. His mature system is speculative, but it grows from respect for mathematics, physics, and concrete experience. Another mistake is to treat process philosophy as the simple claim that everything changes. Whitehead's question is how change, order, value, and relation can be metaphysically basic.`,
      `Begin with Science and the Modern World before attempting Process and Reality. The Concept of Nature helps with the philosophy of science background, while Adventures of Ideas shows broader cultural concerns. In Process and Reality, read slowly and keep a glossary of terms such as actual occasion, prehension, concrescence, creativity, and society. Whitehead is difficult because he is building a vocabulary for a world where events, not inert things, do the deepest explanatory work.`,
      `The safest beginner strategy is to keep asking what ordinary dualism Whitehead is trying to avoid. He resists mind versus nature, value versus fact, static being versus change, and science versus concrete experience. Not every reader will accept the full system, and many details remain disputed. But the pressure behind the system is durable: if modern knowledge divides reality into pieces that no longer fit together, philosophy has to ask whether the dividing concepts are the problem.`,
      `Whitehead is also worth reading slowly because his system turns familiar nouns into activities. Nature becomes event, object becomes society, perception becomes prehension, and order becomes a fragile achievement within creativity. This shift can feel disorienting, but it is the point. He is training the reader to stop imagining process as something added to stable things and to see stability as a pattern generated inside process itself.`,
      `The reward is a vocabulary for problems that still press on philosophy: how mind belongs to nature, how value fits a scientific world, how novelty is possible, and how abstraction can serve knowledge without replacing the concrete world it was meant to illuminate.`
    ],['metaphysics','philosophy-of-science'],['whitehead','russell','william-james'],['Science and the Modern World','The Concept of Nature','Process and Reality','Adventures of Ideas'])
  ],
  popper:[
    section('overview','Critical rationalism and scientific testing',[
      `Karl Popper is one of the most influential philosophers of science of the twentieth century because he made criticism, testing, and falsifiability central to the image of science. He opposed the idea that science advances by accumulating certain confirmations through induction. Instead, scientists propose bold conjectures and expose them to severe attempts at refutation. Knowledge grows by error correction.`,
      `Popper matters beyond a slogan about falsifiability. His philosophy connects scientific method with fallibilism, rational criticism, political openness, and resistance to historical determinism. He thought no theory is finally verified, but some theories are better because they take greater risks and survive harder tests. The result is not skepticism. It is a disciplined confidence in institutions and practices that make criticism possible.`
    ],['philosophy-of-science','epistemology','political-philosophy'],['popper','peirce','kuhn'],['The Logic of Scientific Discovery','Conjectures and Refutations']),
    section('historical-context','Vienna, logical empiricism, and the problem of demarcation',[
      `Popper developed his early philosophy in conversation and tension with the Vienna Circle and logical empiricism. The logical empiricists sought to clarify scientific meaning, often through verification, logic, and the analysis of language. Popper shared their admiration for science and their suspicion of obscurantism, but he rejected verification as the defining mark of science. Universal scientific laws cannot be conclusively verified by finite observations.`,
      `The demarcation problem asks what distinguishes empirical science from non-science or pseudoscience. Popper's answer is falsifiability: a scientific theory must forbid some possible observations and therefore risk conflict with experience. This standard was aimed partly at theories he thought too flexible, able to explain any outcome after the fact. A theory that is compatible with everything gains no empirical grip.`
    ],['philosophy-of-science','analytic-philosophy','logic'],['popper','carnap'],['The Logic of Scientific Discovery']),
    section('falsifiability','Falsifiability and empirical risk',[
      `Falsifiability does not mean that a theory is false. It means that the theory makes claims that could, in principle, be shown false by observation under relevant conditions. Newtonian mechanics, for example, was scientific not because it was beyond challenge, but because it made precise predictions that could be tested. A theory has empirical content by ruling out possibilities.`,
      `This idea is powerful because it connects meaning, risk, and method. A claim protected from every possible counterexample may be metaphysical, mathematical, moral, or simply vague, but it is not empirical science in Popper's sense. Yet applying falsifiability is not always simple. Auxiliary assumptions, measurement error, background theory, and experimental design complicate the relation between theory and observation. Popper knew this, but he still insisted that science requires exposure to potential defeat.`
    ],['philosophy-of-science','epistemology'],['popper','carnap','quine'],['The Logic of Scientific Discovery']),
    section('conjectures-refutations','Conjectures and refutations',[
      `Popper's positive model of knowledge growth is conjectures and refutations. We begin with problems, propose tentative solutions, derive consequences, and criticize them. Refuted theories teach us by showing where our expectations fail. Surviving theories are not proven true, but they may be corroborated by severe tests. Knowledge advances through selection among attempted solutions rather than through a secure foundation of certainty.`,
      `This model gives creativity and criticism complementary roles. Without bold conjectures, there is nothing interesting to test. Without criticism, conjectures harden into dogma. Popper therefore values theories that explain much, make risky predictions, and expose themselves to possible failure. The scientist is not an inductive collector of neutral facts, but an imaginative problem solver whose proposals must face disciplined attempts at rejection.`
    ],['philosophy-of-science','epistemology'],['popper','peirce'],['Conjectures and Refutations']),
    section('induction','The problem of induction',[
      `Popper's rejection of induction responds to a problem made famous by Hume: no finite set of past observations logically guarantees a universal law about future cases. Seeing many white swans does not prove that all swans are white. Popper accepts the force of this problem and denies that science needs inductive justification in the traditional sense. Science does not infer certainty from repeated instances.`,
      `Instead, universal theories are guesses tested by their consequences. We can deductively refute a universal claim if an accepted counter-instance conflicts with it, but we cannot deductively verify it by accumulating positive cases. This asymmetry supports Popper's method. Critics argue that scientists often rely on confirmation, probability, and comparative support in ways Popper underplays. Still, his anti-inductivism remains a landmark attempt to build rational science without impossible certainty.`
    ],['epistemology','philosophy-of-science'],['popper','hume'],['The Logic of Scientific Discovery','An Enquiry Concerning Human Understanding']),
    section('corroboration','Corroboration, severity, and probability',[
      `Popper distinguishes corroboration from verification. A theory is corroborated when it has survived serious tests, especially tests that could easily have gone against it. Corroboration is historical and methodological, not a guarantee of truth. It reports how well a theory has performed under criticism. A weak test adds little, while a severe test can make survival significant.`,
      `Popper was suspicious of treating scientific support as high probability in a simple sense. Bold universal theories may be improbable if measured against the vast space of possibilities, yet scientifically valuable because they say a great deal and risk much. The important question is not whether a theory has been made safe by positive instances, but whether it has faced the kinds of criticism that would expose its weaknesses.`
    ],['philosophy-of-science','logic','epistemology'],['popper','carnap'],['The Logic of Scientific Discovery']),
    section('metaphysics-science','Metaphysics and science',[
      `Although Popper uses falsifiability to demarcate empirical science, he does not think all non-falsifiable ideas are meaningless. Some metaphysical ideas can guide research, frame problems, or later become testable in modified form. He rejects the strongest verificationist impulse to dismiss metaphysics as nonsense. The boundary between science and non-science is methodological, not a simple boundary between sense and nonsense.`,
      `This nuance is important because Popper's own worldview includes broad metaphysical commitments about realism, rationality, and the openness of the future. He thinks the external world exists independently of our theories, and he treats truth as a regulative aim even though certainty is unavailable. Scientific theories are human constructions, but they are constructions answerable to a world that can resist them.`
    ],['philosophy-of-science','metaphysics','epistemology'],['popper','carnap'],['Conjectures and Refutations']),
    section('open-society','The open society and criticism in politics',[
      `Popper's political philosophy extends his fallibilism into public life. In The Open Society and Its Enemies, he criticizes forms of historicism and authoritarian politics that claim to know the necessary direction of history. If no person or party possesses final knowledge, political institutions should allow criticism, replacement of rulers, protection of dissent, and correction of mistakes without catastrophe.`,
      `The connection between science and politics is not that society should be run by scientists. It is that rational life depends on the possibility of criticism. Closed societies protect doctrines from challenge; open societies build institutions through which errors can be exposed and repaired. Popper's liberalism is therefore epistemic as well as moral. Human beings are fallible, so they need practices that make learning possible.`
    ],['political-philosophy','epistemology','philosophy-of-science'],['popper','plato','marx'],['The Open Society and Its Enemies','The Poverty of Historicism']),
    section('historicism','Historicism and prediction',[
      `Popper uses historicism for approaches that claim to discover laws of historical development capable of predicting humanity's future path. He thinks this ambition misunderstands history because future knowledge affects future events, and future knowledge cannot be predicted in detail in advance. Societies change partly through ideas, discoveries, technologies, and decisions that are not available before they occur.`,
      `His critique is directed at grand theories that turn politics into obedience to an alleged destiny. Popper does not deny that social science can identify tendencies, institutions, incentives, and unintended consequences. He denies that it can provide prophetic certainty. The practical alternative is piecemeal social engineering: propose reforms, test consequences, correct errors, and avoid revolutionary projects that sacrifice present people to a supposed inevitable future.`
    ],['political-philosophy','philosophy-of-science'],['popper','marx','hegel'],['The Poverty of Historicism','The Open Society and Its Enemies']),
    section('kuhn-lakatos','Popper, Kuhn, and later philosophy of science',[
      `Popper influenced and provoked later philosophers of science. Thomas Kuhn challenged the image of science as a constant sequence of individual falsifications by emphasizing paradigms, normal science, crises, and revolutions. Imre Lakatos tried to mediate by speaking of research programmes with hard cores and protective belts. These debates made philosophy of science more historically and socially aware.`,
      `Popper's defenders argue that his account is a norm of rational criticism rather than a complete sociology of scientific behavior. Critics reply that real scientists do not abandon theories at the first anomaly and that observation is shaped by paradigms and background commitments. The best approach is to see Popper as articulating a powerful ideal of critical testing that must be supplemented by historical attention to how scientific communities actually work.`
    ],['philosophy-of-science','epistemology'],['popper','kuhn'],['The Logic of Scientific Discovery','The Structure of Scientific Revolutions']),
    section('objective-knowledge','Objective knowledge and the three worlds',[
      `Popper's later work develops an account of objective knowledge that is not confined to private mental states. He distinguishes the physical world, the world of subjective experience, and a third world of objective contents such as theories, arguments, problems, and mathematical structures. These contents are human products, but once produced they can have consequences not intended by their creators. A proof, a problem, or a theory can be criticized and developed by others.`,
      `This view supports Popper's broader anti-subjectivism. Knowledge is not only what someone feels certain about. It includes publicly available problems and proposed solutions that can be examined independently of any one believer's psychology. A scientific theory belongs to this objective domain because it can be tested, compared, refuted, and improved. The growth of knowledge is therefore partly the growth of a shared critical environment.`,
      `The three-worlds language is controversial, and readers need not accept every metaphysical detail to see its purpose. Popper wants to explain how fallible humans can create objective problems that then discipline later thought. A false theory can still be objectively important because it raises questions, suggests experiments, and reveals errors. This fits his image of science as a public adventure in criticism rather than a private accumulation of secure impressions.`
    ],['epistemology','philosophy-of-science','metaphysics'],['popper','frege'],['Objective Knowledge']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `The most common misunderstanding is that Popper thinks one failed prediction should instantly destroy any theory. In practice, tests involve instruments, auxiliary hypotheses, and judgment about where the error lies. Another mistake is to reduce him to a checklist for calling something pseudoscience. His deeper project is critical rationalism: the view that reason advances by exposing claims to criticism rather than securing them against all possible doubt.`,
      `Begin with Conjectures and Refutations for accessible statements, then read The Logic of Scientific Discovery for the technical program. The Open Society and Its Enemies shows how the same fallibilist spirit enters politics, though it should be read critically and historically. Popper is strongest when read as a philosopher of disciplined criticism: he teaches that rational confidence comes from tests survived, not from immunity to challenge.`,
      `His limits should be part of the reading strategy. Actual science often protects promising theories while researchers examine instruments, background assumptions, and alternative explanations. Historical cases rarely look as clean as a textbook falsification. Popper is still powerful because he names a norm that scientific communities ignore at their peril: theories must remain vulnerable to public criticism. Read him as giving a critical ethic for inquiry, then read Kuhn and later philosophers to understand how that ethic operates inside real traditions of practice.`,
      `A helpful comparison is with Peirce. Both philosophers are fallibilists, both reject final certainty, and both treat inquiry as answerable to a reality that can correct us. Peirce emphasizes the long-run community of inquiry and the logic of signs; Popper emphasizes bold conjectures, severe criticism, and institutional openness. Together they show two sides of a non-dogmatic realism: truth is not possessed, but methods can be better or worse at letting the world expose our mistakes.`,
      `That comparison also keeps Popper from becoming merely negative. Refutation matters because problems matter. The point of criticism is not to enjoy demolition but to replace weaker solutions with stronger ones. Popper's rationalism is hopeful precisely because it treats error as something a community can use. His best reader learns to welcome criticism as a condition of intellectual progress, not as a personal defeat.`
    ],['philosophy-of-science','epistemology','political-philosophy'],['popper','peirce','kuhn'],['Conjectures and Refutations','The Logic of Scientific Discovery','The Open Society and Its Enemies'])
  ],
  kuhn:[
    section('overview','Science as historical practice',[
      `Thomas Kuhn changed philosophy of science by making the history of science central to philosophical reflection. The Structure of Scientific Revolutions argues that scientific development is not simply the steady accumulation of facts under one permanent method. Mature sciences work within paradigms, pursue normal research, encounter anomalies, enter crises, and sometimes undergo revolutions that reorganize standards, problems, and world pictures.`,
      `Kuhn matters because he made scientific rationality look more historically situated without simply dismissing science as irrational. He began as a physicist and historian of science, and his philosophical force comes from close attention to episodes such as Copernican astronomy, Newtonian mechanics, chemistry, and modern physics. His work asks how communities learn, how standards change, and how a scientific world can be transformed while still remaining answerable to evidence.`
    ],['philosophy-of-science','epistemology'],['kuhn','popper','carnap'],['The Structure of Scientific Revolutions']),
    section('historical-background','From physics to history of science',[
      `Kuhn's early training in physics shaped his sensitivity to the internal standards of scientific work. His turn toward history showed him that past scientists were not simply modern scientists with fewer facts. They often worked within different conceptual worlds, with different problems, instruments, classifications, and standards of explanation. Understanding them requires reconstructing their practice rather than judging them only by later textbooks.`,
      `The Copernican Revolution already displays this approach. Kuhn asks how astronomy changed not merely because new observations appeared, but because mathematical, physical, theological, and aesthetic considerations interacted over time. Scientific change involves education, models, exemplars, technical puzzles, and broader metaphysical commitments. This historical sensibility made Kuhn suspicious of simplified philosophical accounts that describe method without studying actual scientific development.`
    ],['philosophy-of-science','epistemology'],['kuhn'],['The Copernican Revolution']),
    section('paradigm','Paradigms and disciplinary matrices',[
      `Kuhn's most famous term is paradigm, though he later clarified it because readers used it too broadly. A paradigm can mean an exemplary scientific achievement that guides future work, such as Newton's mechanics, and it can also refer to the wider disciplinary matrix of commitments, instruments, values, and techniques shared by a scientific community. Paradigms tell scientists what counts as a problem and what counts as a solution.`,
      `This does not mean scientists blindly obey a doctrine. A paradigm is productive because it opens a field of research. It supplies models, puzzles, standards of precision, and expectations about what nature is like. Students learn it through textbooks, problem sets, laboratory practice, and exemplars. Much scientific competence is therefore practical and trained, not merely the possession of explicit methodological rules.`
    ],['philosophy-of-science','epistemology'],['kuhn'],['The Structure of Scientific Revolutions']),
    section('normal-science','Normal science and puzzle-solving',[
      `Kuhn's normal science is research conducted under an accepted paradigm. It is not dull or uncritical in the ordinary sense. It can be technically demanding and creative, but its creativity is directed toward solving puzzles whose general form is assumed to be legitimate. Normal scientists refine measurements, extend theory, articulate details, and bring nature and paradigm into closer fit.`,
      `This idea challenged heroic images of science as constant foundational doubt. Most scientists most of the time do not test the whole framework at once. They rely on it in order to do detailed work. Kuhn thinks this trust is necessary for depth. Without shared commitments, research would scatter. The same commitment that makes normal science productive can also make anomalies difficult to recognize as signs of deeper trouble.`
    ],['philosophy-of-science'],['kuhn','popper'],['The Structure of Scientific Revolutions']),
    section('anomaly-crisis','Anomalies, crisis, and loss of confidence',[
      `An anomaly is a result or problem that resists expected solution within a paradigm. Normal science can tolerate many anomalies because no theory fits every detail perfectly at every moment. Scientists may assume that better measurements, auxiliary hypotheses, or further work will resolve the difficulty. An anomaly becomes crisis-producing only when it strikes central expectations and resists repeated repair.`,
      `Crisis weakens confidence in the old framework and encourages exploration of alternatives. During crisis, debates become more philosophical because basic standards and concepts are in question. Scientists may disagree not only about answers but about what would count as a good answer. Kuhn's point is not that evidence stops mattering. It is that evidence is interpreted through frameworks, and when frameworks themselves are contested, evaluation becomes more complex.`
    ],['philosophy-of-science','epistemology'],['kuhn'],['The Structure of Scientific Revolutions']),
    section('revolution','Scientific revolutions and world change',[
      `A scientific revolution occurs when one paradigm is replaced by another in a way that reorganizes the field. The shift from Ptolemaic to Copernican astronomy, from phlogiston chemistry to oxygen chemistry, or from classical to relativistic physics involves more than adding facts. It changes taxonomies, standards, explanatory ideals, and the meaning of central terms. Kuhn sometimes says scientists after a revolution work in a different world.`,
      `That phrase should be read carefully. Kuhn is not claiming that planets or chemicals are created by theories. He is saying that the experienced and investigated world of the scientist is structured by concepts, instruments, and practices. After a revolution, old data may be redescribed, old problems may disappear, and new problems may become urgent. Scientific progress includes discontinuity as well as accumulation.`
    ],['philosophy-of-science','epistemology'],['kuhn','popper'],['The Structure of Scientific Revolutions']),
    section('incommensurability','Incommensurability and translation',[
      `Kuhn's idea of incommensurability says that rival paradigms may lack a neutral common measure for direct comparison on every point. Their terms, standards, and problem fields can differ so deeply that translation becomes partial and difficult. Mass, element, planet, or motion may not function the same way across scientific frameworks. This complicates the idea that choice between theories is always a straightforward comparison using fixed criteria.`,
      `Incommensurability does not mean incomparability in an absolute sense. Scientists can and do argue across paradigms, point to successes and failures, and learn each other's languages. Kuhn's point is that comparison requires interpretive work and cannot always be reduced to a single algorithm. This insight made philosophy of science more attentive to language, training, practice, and the historical evolution of standards.`
    ],['philosophy-of-science','philosophy-of-language','epistemology'],['kuhn','quine'],['The Structure of Scientific Revolutions','The Road Since Structure']),
    section('values-choice','Values in theory choice',[
      `Kuhn identifies values such as accuracy, consistency, scope, simplicity, and fruitfulness as important in theory choice. These values guide scientific judgment, but they do not always point in the same direction or determine one unique answer. Scientists may weigh them differently, especially during crisis. This leaves room for judgment without implying that theory choice is arbitrary.`,
      `The role of values helps explain both rationality and disagreement. A new theory may be less accurate in some early applications but more fruitful for new research. An older theory may be simpler in one respect and less coherent with neighboring fields. Kuhn's account respects the fact that scientific decisions are made by trained communities using shared values, not by machines applying timeless rules without interpretation.`
    ],['philosophy-of-science','epistemology'],['kuhn','popper'],['The Essential Tension']),
    section('relativism-question','The charge of relativism',[
      `Kuhn was often accused of making science irrational or relativistic. The charge is understandable because he emphasizes paradigms, conversion-like shifts, and the absence of a neutral algorithm. But Kuhn does not say that evidence is irrelevant or that every paradigm is as good as every other. He argues that rational evaluation is historically situated, value-laden, and community-based rather than governed by one permanent logical formula.`,
      `His view is strongest when read as a correction to overly simple images of method. Science is rational, but its rationality is embodied in training, exemplars, instruments, journals, standards, and communities. Progress is real, but it may not be progress toward a single fixed vocabulary that simply accumulates all earlier truths unchanged. Kuhn asks philosophers to explain science as practiced, not science as imagined by methodological slogans.`
    ],['philosophy-of-science','epistemology'],['kuhn','popper','carnap'],['The Structure of Scientific Revolutions']),
    section('popper-and-after','Popper, logical empiricism, and later debates',[
      `Kuhn's relation to Popper is central. Popper emphasizes bold conjectures and severe attempts at refutation, while Kuhn emphasizes normal science and the fact that scientists usually do not abandon a paradigm because of one anomaly. Popper gives a norm of critical rationality; Kuhn gives a historically informed account of scientific development. The tension between them shaped later philosophy of science.`,
      `Kuhn also transformed debates inherited from logical empiricism. Questions about confirmation, language, and theory structure became entangled with history, education, and community practice. Later philosophers debated whether Kuhn had exaggerated discontinuity, underplayed realism, or opened the door to sociology of science. Even critics had to respond to his historical challenge: any philosophy of science must fit the record of actual scientific change.`
    ],['philosophy-of-science','analytic-philosophy','epistemology'],['kuhn','popper','carnap','quine'],['The Structure of Scientific Revolutions','Conjectures and Refutations']),
    section('textbooks-education','Textbooks, education, and invisible history',[
      `Kuhn pays close attention to scientific education because textbooks shape how scientists learn their field. Textbooks usually present solved problems, cleaned-up methods, and a sequence of achievements leading naturally to current theory. That pedagogy is useful for training normal scientists, but it can hide the conflicts, false starts, metaphysical assumptions, and alternative paths that marked actual discovery. The past becomes a prelude to the present.`,
      `This matters because scientific memory affects philosophical interpretation. If students learn only the polished textbook version, they may assume that science always advances by a simple method applied to neutral facts. Historical study reveals a more complex process in which standards, instruments, concepts, and communities develop together. Kuhn is not attacking textbooks for doing their job. He is warning philosophers not to mistake pedagogical reconstruction for historical reality.`,
      `The emphasis on education also explains why paradigms are so durable. They are not merely explicit theses one can reject after reading a counterargument. They are embodied in problem-solving habits, laboratory expectations, diagrams, examples, and judgments about elegance or promise. Paradigm change therefore requires retraining perception and practice, not only changing a sentence in a theory. That is why scientific revolutions can be rational and still feel disruptive to those living through them.`
    ],['philosophy-of-science','epistemology'],['kuhn','dewey'],['The Structure of Scientific Revolutions','The Essential Tension']),
    section('misunderstandings-reading','Misunderstandings and reading strategy',[
      `The most common misunderstanding is that Kuhn thinks science is just politics or fashion. He does not. He thinks science is a disciplined practice whose standards are learned inside historical communities. Another misunderstanding is that paradigms are merely worldviews. They are also concrete exemplars, problem solutions, instruments, and habits of trained judgment. The practical side matters as much as the conceptual side.`,
      `Begin with The Structure of Scientific Revolutions, but read it as a compressed argument shaped by historical examples rather than as a complete theory of everything. The Copernican Revolution gives a fuller historical case. The Essential Tension and later essays clarify paradigms, values, and incommensurability. Kuhn is best read beside Popper: one highlights criticism, the other the historical conditions that make scientific criticism possible and consequential.`,
      `A strong reading also keeps Kuhn's historian's discipline in view. He is not asking philosophers to abandon rational standards, but to notice that standards themselves have histories. That can be unsettling because it removes the fantasy of a method that judges every episode from nowhere. It also makes science more impressive, not less. Scientific communities build ways of seeing, testing, teaching, and correcting that can transform their own standards under pressure from problems they cannot solve.`,
      `The continuing value of Kuhn is that he makes scientific knowledge look human without making it merely subjective. Instruments have to be built, students trained, journals persuaded, anomalies interpreted, and older vocabularies reworked. None of that cancels evidence. It explains how evidence becomes visible and forceful within a practice. Kuhn's philosophy is therefore a warning against both naive method worship and easy cynicism about science.`,
      `For a beginner, the best final question is not whether Kuhn defeated objectivity, but what kind of objectivity survives history. His answer points toward trained judgment, shared standards, material resistance, and communities able to revise even their deepest habits when anomalies become impossible to ignore. That question keeps the drama of revolutions connected to the ordinary discipline of scientific work.`
    ],['philosophy-of-science','epistemology'],['kuhn','popper'],['The Structure of Scientific Revolutions','The Copernican Revolution','The Essential Tension','The Road Since Structure'])
  ]
};
